const command = $json.command || '';

// --- KEEP: Basic security to prevent shell injection ---
const chainPatterns = [';', '&&', '||', '|', '`', '$('];
for (const p of chainPatterns) {
  if (command.includes(p)) {
    throw new Error(`Blocked: command contains disallowed chaining/substitution sequence "${p}"`);
  }
}

// --- KEEP: Block access to highly sensitive paths/files ---
const forbiddenPathPatterns = [
  /\.env\b/i,
  /\.ssh\//i,
  /id_rsa/i,
  /credentials/i,
  /\.bash_history/i,
  /\.mysql_history/i,
  /\/etc\/shadow/i,
  /\/etc\/passwd/i,
  /\.sql\b/i,
  /\.dump\b/i
];
for (const re of forbiddenPathPatterns) {
  if (re.test(command)) {
    throw new Error(`Blocked: command references a forbidden path or credential pattern (matched ${re})`);
  }
}

// --- REMOVED: The forbiddenScope block blocking Nginx and other services has been deleted to allow generalized infrastructure management. ---

return [{ json: { command } }];

const maxLength = 3000;

function truncate(str) {
  if (typeof str !== 'string' || str.length <= maxLength) return str;
  return str.slice(0, maxLength) + `\n...[truncated ${str.length - maxLength} characters]`;
}

return $input.all().map(item => {
  const data = { ...item.json };
  data.stdout = truncate(data.stdout);
  data.stderr = truncate(data.stderr);
  return { json: data };
});
